201→bool ALFPHexGridManager::LoadMapFromCSV(const FString& CSVFilePath)
202→{
203→	FString CSVContent;
204→	if (!FFileHelper::LoadFileToString(CSVContent, *CSVFilePath))
205→	{
206→		UE_LOG(LogTemp, Error, TEXT("LoadMapFromCSV: 无法加载文件 %s"), *CSVFilePath);
207→		return false;
208→	}
209→
210→	// 使用临时 DataTable 解析 CSV
211→	UDataTable* TempTable = NewObject<UDataTable>(GetTransientPackage());
212→	TempTable->RowStruct = FLFPMapTileRow::StaticStruct();
213→
214→	TArray<FString> Problems = TempTable->CreateTableFromCSVString(CSVContent);
215→	if (Problems.Num() > 0)
216→	{
217→		for (const FString& Problem : Problems)
218→		{
219→			UE_LOG(LogTemp, Warning, TEXT("CSV 解析问题: %s"), *Problem);
220→		}
221→	}
222→
223→	LoadMapFromDataTable(TempTable);
224→	return true;
225→}
